import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ItineraryDisplay } from './components/ItineraryDisplay';
import { MarketInsights } from './components/MarketInsights';
import { ErrorBanner } from './components/ErrorBanner';
import { useItinerary } from './hooks/useItinerary';
import { useMarketInsights } from './hooks/useMarketInsights';
import { DEFAULT_FORM_DATA } from './constants';
import { MapPin, TrendingUp, Compass } from 'lucide-react';

type ViewMode = 'planner' | 'insights';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewMode>('planner');
  const [showResultsMobile, setShowResultsMobile] = useState(false);

  // Use Custom Hooks
  const { 
    itinerary, 
    isLoading, 
    error, 
    validationErrors, 
    lastData, 
    handleGenerate, 
    setError 
  } = useItinerary();

  const { insights, isInsightsLoading, fetchInsights } = useMarketInsights();

  const onFormSubmit = async (data: any, isAlt: boolean) => {
    const success = await handleGenerate(data, isAlt);
    if (success && window.innerWidth < 1024) {
      setShowResultsMobile(true);
    }
  };

  const switchView = (view: ViewMode) => {
    setCurrentView(view);
    // Lazy load insights when switching to tab if not already loaded
    if (view === 'insights' && !insights && !isInsightsLoading) {
        fetchInsights();
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-[#222222] font-sans">
      {/* Header Section */}
      <header className="flex-none bg-white border-b border-gray-200 z-50 sticky top-0 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 text-[#FF385C] cursor-pointer" onClick={() => switchView('planner')}>
            <MapPin className="w-8 h-8 fill-current" />
            <h1 className="text-2xl font-bold tracking-tight text-[#FF385C] hidden sm:block">
              RoadTripPro
            </h1>
          </div>

          <nav className="flex items-center gap-6">
            <NavButton 
              active={currentView === 'planner'} 
              onClick={() => switchView('planner')} 
              icon={<Compass className="w-4 h-4" />}
              label="Road Trip" 
            />
            <NavButton 
              active={currentView === 'insights'} 
              onClick={() => switchView('insights')} 
              icon={<TrendingUp className="w-4 h-4" />}
              label="Market Insights" 
            />
          </nav>

          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-gray-100 border border-gray-200 flex items-center justify-center text-gray-500 hover:shadow-md transition-shadow cursor-pointer">
                <span className="text-xs font-bold">JD</span>
             </div>
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        <div className="max-w-7xl mx-auto h-full p-0 lg:p-6">

          {currentView === 'planner' ? (
             <div className="flex flex-col lg:flex-row gap-8 h-full">
                {/* Form Column */}
                <div className={`w-full lg:w-[400px] flex-none h-full bg-white lg:rounded-2xl lg:shadow-xl lg:border lg:border-gray-100 overflow-hidden flex flex-col z-20 transition-transform duration-300 ${showResultsMobile ? '-translate-x-full absolute' : 'translate-x-0 relative'} lg:translate-x-0 lg:relative`}>
                    <InputForm 
                      initialData={DEFAULT_FORM_DATA} 
                      onSubmit={onFormSubmit}
                      isLoading={isLoading}
                      validationErrors={validationErrors}
                    />
                    {error && (
                        <ErrorBanner message={error} onClose={() => setError(null)} />
                    )}
                </div>

                {/* Display Column */}
                <div className={`flex-1 h-full overflow-hidden bg-white lg:bg-transparent rounded-none lg:rounded-2xl relative transition-transform duration-300 ${showResultsMobile ? 'translate-x-0 absolute inset-0 z-30' : 'translate-x-full absolute'} lg:translate-x-0 lg:relative lg:inset-auto lg:z-0`}>
                    {showResultsMobile && (
                        <div className="lg:hidden absolute top-4 left-4 z-50">
                            <button 
                            onClick={() => setShowResultsMobile(false)}
                            className="bg-white p-2 rounded-full shadow-lg border border-gray-100 text-gray-700 font-bold text-sm px-4 flex items-center gap-2"
                            >
                            <span>←</span> Edit Plan
                            </button>
                        </div>
                    )}

                    <ItineraryDisplay 
                      itinerary={itinerary} 
                      isLoading={isLoading} 
                      onGenerateAlternative={() => {
                        if (lastData) {
                          onFormSubmit(lastData, true);
                        }
                      }}
                    />
                </div>
             </div>
          ) : (
             <div className="h-full bg-transparent">
                 <MarketInsights 
                    insights={insights} 
                    isLoading={isInsightsLoading} 
                    onRefresh={fetchInsights} 
                 />
             </div>
          )}

        </div>
      </main>
    </div>
  );
};

// Helper sub-component for nav buttons
const NavButton: React.FC<{ active: boolean, onClick: () => void, icon: React.ReactNode, label: string }> = ({ active, onClick, icon, label }) => (
  <button 
      onClick={onClick}
      className={`py-2 transition-colors flex items-center gap-2 text-sm font-semibold ${active ? 'text-gray-900 border-b-2 border-gray-900' : 'text-gray-500 hover:text-gray-800'}`}
  >
      {icon}
      {label}
  </button>
);

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Plus, X, MapPin, Calendar, Clock, Car, Bus, Plane, Shuffle, Search, Info, Edit2, Check, ChevronDown, AlertCircle, Sparkles, Trash2, Moon, Locate, LocateFixed, Train } from 'lucide-react';
import { TripFormData, TravelMode, MandatoryStop, ValidationErrors, MixedTravelLeg } from '../types';
import { DEFAULT_FORM_DATA } from '../constants';

interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
  validationErrors?: ValidationErrors;
}

const STORAGE_KEY = 'roadTripPro_formData';

const EMPTY_STOP: MandatoryStop = { location: '', date: '', arrivalDate: '', nights: 1 };

// Simulated Database for Autocomplete
const POPULAR_CITIES = [
  "New York, NY", "Los Angeles, CA", "Chicago, IL", "Houston, TX", "Phoenix, AZ",
  "Philadelphia, PA", "San Antonio, TX", "San Diego, CA", "Dallas, TX", "San Jose, CA",
  "Austin, TX", "Jacksonville, FL", "Fort Worth, TX", "Columbus, OH", "San Francisco, CA",
  "Charlotte, NC", "Indianapolis, IN", "Seattle, WA", "Denver, CO", "Washington, DC",
  "Boston, MA", "El Paso, TX", "Nashville, TN", "Detroit, MI", "Oklahoma City, OK",
  "Portland, OR", "Las Vegas, NV", "Memphis, TN", "Louisville, KY", "Baltimore, MD",
  "Milwaukee, WI", "Albuquerque, NM", "Tucson, AZ", "Fresno, CA", "Sacramento, CA",
  "Kansas City, MO", "Mesa, AZ", "Atlanta, GA", "Omaha, NE", "Colorado Springs, CO",
  "Raleigh, NC", "Miami, FL", "Long Beach, CA", "Virginia Beach, VA", "Oakland, CA",
  "Minneapolis, MN", "Tulsa, OK", "Tampa, FL", "Arlington, TX", "New Orleans, LA"
];

// Helper for robust ID generation across environments
const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    try {
      return crypto.randomUUID();
    } catch (e) {
      // Fallback if crypto exists but randomUUID fails (rare context issues)
    }
  }
  return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading, validationErrors }) => {
  // Initialize state from localStorage or fall back to initialData
  const [formData, setFormData] = useState<TripFormData>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      // Merge with default to ensure new fields like mixedTravelLegs exist
      return saved ? { ...DEFAULT_FORM_DATA, ...JSON.parse(saved) } : initialData;
    } catch (e) {
      console.warn('Failed to load form data from local storage', e);
      return initialData;
    }
  });

  // Modal State
  const [isStopModalOpen, setIsStopModalOpen] = useState(false);
  const [editingIndex, setEditingIndex] = useState<number | null>(null); // null means adding new
  const [tempStop, setTempStop] = useState<MandatoryStop>(EMPTY_STOP);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);

  // Autocomplete State for Stop Modal
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // Autocomplete State for Destination
  const [destSuggestions, setDestSuggestions] = useState<string[]>([]);
  const [showDestSuggestions, setShowDestSuggestions] = useState(false);

  // Persist to localStorage whenever formData changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
    } catch (e) {
      console.warn('Failed to save form data to local storage', e);
    }
  }, [formData]);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // --- Mixed Mode Legs Logic ---
  const addLeg = () => {
      const newLeg: MixedTravelLeg = {
          id: generateId(),
          mode: 'Flight',
          description: '',
          estimatedDuration: ''
      };
      handleChange('mixedTravelLegs', [...(formData.mixedTravelLegs || []), newLeg]);
  };

  const updateLeg = (id: string, field: keyof MixedTravelLeg, value: string) => {
      const updated = (formData.mixedTravelLegs || []).map(leg => 
          leg.id === id ? { ...leg, [field]: value } : leg
      );
      handleChange('mixedTravelLegs', updated);
  };

  const deleteLeg = (id: string) => {
      const updated = (formData.mixedTravelLegs || []).filter(leg => leg.id !== id);
      handleChange('mixedTravelLegs', updated);
  };

  // --- Geolocation Logic ---
  const performGeolocation = useCallback((isAuto: boolean) => {
    // Clear previous errors before starting
    setLocationError(null);

    if (!navigator.geolocation) {
      if (!isAuto) setLocationError("Geolocation is not supported by your browser");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;

        try {
            // Using BigDataCloud API for reliable city/state names (Free, robust for client-side)
            const response = await fetch(
                `https://api.bigdatacloud.net/data/reverse-geocode-client?latitude=${latitude}&longitude=${longitude}&localityLanguage=en`
            );

            if (!response.ok) throw new Error('Geocoding failed');

            const data = await response.json();

            // Extract meaningful names with fallbacks
            const city = data.city || data.locality || '';
            const state = data.principalSubdivisionCode || data.principalSubdivision || '';
            const country = data.countryCode || '';

            let locString = '';

            if (city) {
                locString = city;
                if (state) locString += `, ${state}`;
                else if (country) locString += `, ${country}`;
            } else if (state) {
                 // Fallback: State, Country if city is undefined (rural areas)
                 locString = `${state}, ${country}`;
            }

            if (!locString.trim()) {
                 locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;
            }

            setFormData(prev => ({ ...prev, origin: locString }));
        } catch (error) {
            console.warn("Reverse geocoding failed", error);
            const locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;
            setFormData(prev => ({ ...prev, origin: locString }));
        } finally {
            setIsLocating(false);
        }
      },
      (error) => {
        console.error("Geolocation error:", error);
        if (!isAuto) {
            let msg = "Unable to retrieve location";
            if (error.code === 1) msg = "Location permission denied";
            else if (error.code === 2) msg = "Position unavailable";
            else if (error.code === 3) msg = "Request timed out";
            setLocationError(msg);
        }
        setIsLocating(false);
      }
    );
  }, []);

  useEffect(() => {
    if (!formData.origin) {
        performGeolocation(true);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleGeolocationClick = () => {
    performGeolocation(false);
  };

  // --- Modal Logic ---

  const openAddStopModal = () => {
    setTempStop({ ...EMPTY_STOP });
    setSuggestions([]);
    setShowSuggestions(false);
    setEditingIndex(null);
    setIsStopModalOpen(true);
  };

  const openEditStopModal = (index: number) => {
    setTempStop({ ...formData.mandatoryStops[index] });
    setSuggestions([]);
    setShowSuggestions(false);
    setEditingIndex(index);
    setIsStopModalOpen(true);
  };

  const handleTempStopChange = (field: keyof MandatoryStop, value: string | number) => {
    setTempStop(prev => ({ ...prev, [field]: value }));
  };

  // Stop Autocomplete Logic
  const handleCityInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    handleTempStopChange('location', value);

    if (value.length > 1) {
      const filtered = POPULAR_CITIES.filter(city => 
        city.toLowerCase().includes(value.toLowerCase())
      ).slice(0, 5); // Limit to 5 suggestions
      setSuggestions(filtered);
      setShowSuggestions(true);
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
    }
  };

  const selectSuggestion = (city: string) => {
    handleTempStopChange('location', city);
    setShowSuggestions(false);
  };

  // Destination Autocomplete Logic
  const handleDestinationChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    handleChange('destination', value);

    if (value.length > 1) {
      const filtered = POPULAR_CITIES.filter(city => 
        city.toLowerCase().includes(value.toLowerCase())
      ).slice(0, 5); 
      setDestSuggestions(filtered);
      setShowDestSuggestions(true);
    } else {
      setDestSuggestions([]);
      setShowDestSuggestions(false);
    }
  };

  const selectDestSuggestion = (city: string) => {
    handleChange('destination', city);
    setShowDestSuggestions(false);
  };

  const saveStop = () => {
    const newStops = [...formData.mandatoryStops];
    if (editingIndex !== null) {
      newStops[editingIndex] = tempStop;
    } else {
      newStops.push(tempStop);
    }
    handleChange('mandatoryStops', newStops);
    setIsStopModalOpen(false);
  };

  const removeStop = (index: number) => {
    const newStops = formData.mandatoryStops.filter((_, i) => i !== index);
    handleChange('mandatoryStops', newStops);
  };

  const deleteCurrentStop = () => {
    if (editingIndex !== null) {
      removeStop(editingIndex);
    }
    setIsStopModalOpen(false);
  };

  // --- Helper Renderers ---

  const getModeIcon = (mode: string) => {
    // Normalizes input to handle cases like 'Train' vs 'train'
    const normalizedMode = mode?.toLowerCase() || '';
    if (normalizedMode.includes('car')) return <Car className="w-5 h-5" />;
    if (normalizedMode.includes('bus')) return <Bus className="w-5 h-5" />;
    if (normalizedMode.includes('plane') || normalizedMode.includes('flight')) return <Plane className="w-5 h-5" />;
    if (normalizedMode.includes('train')) return <Train className="w-5 h-5" />;
    return <Shuffle className="w-5 h-5" />;
  };

  const renderError = (fieldName: string) => {
      if (!validationErrors || !validationErrors[fieldName]) return null;
      const err = validationErrors[fieldName];
      return (
          <div className="mt-2 flex items-start gap-2 animate-in slide-in-from-top-1 fade-in duration-300">
             <div className="min-w-[4px] h-full bg-red-400 rounded-full mt-1"></div>
             <div>
                <p className="text-xs font-bold text-red-600 leading-tight">{err.message}</p>
                <p className="text-[10px] text-red-400 font-medium mt-0.5 flex items-center gap-1">
                  <Sparkles className="w-3 h-3" />
                  {err.suggestion}
                </p>
             </div>
          </div>
      );
  };

  const getInputClass = (fieldName: string, baseClass: string) => {
      const hasError = validationErrors && validationErrors[fieldName];
      return `${baseClass} ${hasError ? 'bg-red-50/50 text-red-900 placeholder-red-300' : 'bg-transparent text-gray-900 placeholder-gray-400'}`;
  };

  const getContainerClass = (fieldName: string, baseClass: string) => {
       const hasError = validationErrors && validationErrors[fieldName];
       return `${baseClass} ${hasError ? 'bg-red-50 border-red-200' : ''}`;
  };

  return (
    <div className="h-full flex flex-col bg-white relative">
      <div className="p-4 lg:p-6 pb-2 border-b border-gray-100 lg:border-none">
        <h2 className="text-xl lg:text-2xl font-bold text-gray-800">Road Trip Planner</h2>
        <p className="text-gray-500 text-xs lg:text-sm mt-1">Your AI-powered assistant for planning multi-city journeys, helping you discover opportunities.</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-6 custom-scrollbar">
        {/* Origin & Destination Card */}
        <div className={`bg-white border rounded-2xl shadow-[0_6px_16px_rgba(0,0,0,0.08)] overflow-visible transition-colors border-gray-200 z-30 relative`}>
          {/* Origin */}
          <div className={getContainerClass('origin', 'relative p-4 border-b border-gray-100 hover:bg-gray-50 transition-colors rounded-t-2xl')}>
            <div className="flex justify-between items-center mb-1">
                <label className={`text-[10px] font-bold uppercase tracking-wider block ${validationErrors?.origin ? 'text-red-500' : 'text-gray-500'}`}>Origin</label>
                {isLocating && (
                    <span className="text-[10px] font-bold text-blue-500 flex items-center gap-1 animate-pulse">
                        <span className="w-1.5 h-1.5 rounded-full bg-blue-500 inline-block" />
                        Fetching location...
                    </span>
                )}
            </div>
            <div className="flex items-center gap-2">
                <input
                type="text"
                value={formData.origin}
                onChange={(e) => handleChange('origin', e.target.value)}
                className={getInputClass('origin', "w-full font-semibold text-lg focus:outline-none")}
                placeholder="Starting Point (Optional)"
                />
                <button 
                  onClick={handleGeolocationClick}
                  disabled={isLocating}
                  className={`p-2 rounded-full transition-colors ${isLocating ? 'bg-blue-50 text-blue-400' : 'hover:bg-gray-100 text-gray-400 hover:text-[#FF385C]'}`}
                  title="Use Current Location"
                >
                    {isLocating ? <LocateFixed className="w-5 h-5 animate-spin text-blue-500" /> : <Locate className="w-5 h-5" />}
                </button>
            </div>

            {locationError && (
                 <div className="mt-2 p-2 bg-red-50 border border-red-100 rounded-lg flex items-center justify-between animate-in fade-in slide-in-from-top-1">
                    <span className="text-xs font-bold text-red-600 flex items-center gap-1.5">
                        <AlertCircle className="w-3.5 h-3.5" />
                        {locationError}
                    </span>
                    <button 
                        onClick={() => setLocationError(null)}
                        className="p-0.5 hover:bg-red-100 rounded text-red-400 hover:text-red-600 transition-colors"
                    >
                        <X className="w-3.5 h-3.5" />
                    </button>
                 </div>
            )}

            {renderError('origin')}
          </div>

          {/* Destination */}
          <div className={getContainerClass('destination', 'relative p-4 hover:bg-gray-50 transition-colors z-40')}>
            <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.destination ? 'text-red-500' : 'text-gray-500'}`}>Destination</label>
            <div className="relative">
                <input
                    type="text"
                    value={formData.destination}
                    onChange={handleDestinationChange}
                    onBlur={() => setTimeout(() => setShowDestSuggestions(false), 200)}
                    className={getInputClass('destination', "w-full font-semibold text-lg focus:outline-none")}
                    placeholder="Final Destination (Optional)"
                />
                <div className="absolute right-0 top-1/2 -translate-y-1/2 flex items-center gap-2 pointer-events-none">
                     {validationErrors?.destination ? <AlertCircle className="w-5 h-5 text-red-500" /> : <MapPin className="w-5 h-5 text-gray-400" />}
                </div>

                {/* Destination Autocomplete Dropdown */}
                {showDestSuggestions && destSuggestions.length > 0 && (
                    <ul className="absolute z-50 w-full bg-white border border-gray-200 rounded-xl mt-2 shadow-xl max-h-48 overflow-y-auto animate-in fade-in zoom-in-95 duration-150">
                    {destSuggestions.map((city, idx) => (
                        <li 
                            key={`${city}-${idx}`}
                            onMouseDown={() => selectDestSuggestion(city)}
                            className="px-4 py-3 hover:bg-gray-50 cursor-pointer text-sm font-bold text-gray-700 border-b border-gray-50 last:border-none flex items-center gap-2 group transition-colors"
                        >
                            <div className="bg-gray-100 p-1 rounded-full group-hover:bg-[#FF385C] group-hover:text-white transition-colors">
                                <MapPin className="w-3 h-3" />
                            </div>
                            {city}
                        </li>
                    ))}
                    </ul>
                )}
            </div>
             {renderError('destination')}
          </div>
           {/* Destination Date */}
           <div className="relative p-4 border-t border-gray-100 hover:bg-gray-50 transition-colors bg-gray-50/50 rounded-b-2xl">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Target Arrival Date (Optional)</label>
            <input
              type="date"
              value={formData.destinationDate}
              onChange={(e) => handleChange('destinationDate', e.target.value)}
              className="w-full bg-transparent text-gray-700 font-medium focus:outline-none text-base appearance-none min-h-[44px]"
            />
          </div>
        </div>

        {/* Dates Card */}
        <div className={`bg-white border rounded-2xl shadow-[0_6px_16px_rgba(0,0,0,0.08)] overflow-hidden flex flex-col transition-colors border-gray-200`}>
           <div className="flex sm:flex-row flex-col">
              <div className={getContainerClass('startDate', 'flex-1 p-4 border-b sm:border-b-0 sm:border-r border-gray-100 hover:bg-gray-50 transition-colors')}>
                <div className="flex justify-between">
                    <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.startDate ? 'text-red-500' : 'text-gray-500'}`}>Start Date</label>
                    {validationErrors?.startDate && <AlertCircle className="w-3 h-3 text-red-500" />}
                </div>
                <input
                  type="date"
                  value={formData.startDate}
                  onChange={(e) => handleChange('startDate', e.target.value)}
                  className={getInputClass('startDate', "w-full font-medium focus:outline-none text-base appearance-none min-h-[44px]")}
                />
              </div>
              <div className={getContainerClass('endDate', 'flex-1 p-4 hover:bg-gray-50 transition-colors')}>
                <div className="flex justify-between">
                    <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.endDate ? 'text-red-500' : 'text-gray-500'}`}>Return Date</label>
                    {validationErrors?.endDate && <AlertCircle className="w-3 h-3 text-red-500" />}
                </div>
                <input
                  type="date"
                  value={formData.endDate}
                  onChange={(e) => handleChange('endDate', e.target.value)}
                  className={getInputClass('endDate', "w-full font-medium focus:outline-none text-base appearance-none min-h-[44px]")}
                />
              </div>
           </div>
           {(validationErrors?.startDate || validationErrors?.endDate) && (
              <div className="px-4 pb-3 pt-0">
                  {renderError('startDate')}
                  {renderError('endDate')}
              </div>
            )}
        </div>

        {/* Mandatory Stops */}
        <div>
          <div className="flex items-center justify-between mb-3">
             <label className="text-sm font-bold text-gray-800">Must-visit Cities</label>
          </div>

          <div className="space-y-3">
            {formData.mandatoryStops.map((stop, index) => {
              const hasError = validationErrors && validationErrors[`stop_${index}`];
              return (
                <div key={index} className="flex flex-col">
                    <div 
                        onClick={() => openEditStopModal(index)}
                        className={`bg-white border ${hasError ? 'border-red-300' : 'border-gray-200'} hover:border-[#FF385C] rounded-xl p-3 flex items-center justify-between group cursor-pointer transition-all shadow-sm hover:shadow-md`}
                    >
                        <div className="flex items-center gap-3">
                            <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-colors ${hasError ? 'bg-red-50 text-red-500' : 'bg-gray-100 text-gray-500 group-hover:bg-[#FF385C] group-hover:text-white'}`}>
                            <MapPin className="w-4 h-4" />
                            </div>
                            <div>
                            <h4 className={`text-sm font-bold leading-tight ${hasError ? 'text-red-700' : 'text-gray-900'}`}>{stop.location || 'Untitled Stop'}</h4>
                            <div className="flex items-center gap-2 mt-0.5">
                                <span className="text-[10px] text-gray-500 font-medium bg-gray-50 px-1.5 py-0.5 rounded border border-gray-100">
                                    {stop.arrivalDate || stop.date || 'Flexible'}
                                </span>
                                <span className="text-[10px] text-gray-500 font-medium">
                                    {stop.nights} Night{stop.nights !== 1 ? 's' : ''}
                                </span>
                            </div>
                            </div>
                        </div>
                        <div className="text-gray-300 group-hover:text-[#FF385C]">
                            <Edit2 className="w-4 h-4" />
                        </div>
                    </div>
                    {hasError && (
                        <div className="mt-1 ml-2 flex items-center gap-1.5 animate-in fade-in slide-in-from-top-1">
                            <AlertCircle className="w-3 h-3 text-red-500" />
                            <span className="text-xs font-bold text-red-600">{validationErrors[`stop_${index}`].message}</span>
                        </div>
                    )}
                </div>
              );
            })}

            <button
              onClick={openAddStopModal}
              className="w-full py-3 rounded-xl border-2 border-dashed border-gray-200 text-gray-400 font-bold text-sm hover:border-[#FF385C] hover:text-[#FF385C] hover:bg-[#FF385C]/5 transition-all flex items-center justify-center gap-2"
            >
              <Plus className="w-4 h-4" />
              Add Mandatory Stop
            </button>
          </div>
        </div>

        {/* Preferences */}
        <div>
           <label className="text-sm font-bold text-gray-800 mb-3 block">Travel Preferences</label>
           <div className="bg-white border border-gray-200 rounded-2xl p-4 shadow-sm space-y-5">

              {/* Travel Mode */}
              <div>
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block">Mode of Transport</span>
                <div className="grid grid-cols-4 gap-2 mb-3">
                  {Object.values(TravelMode).map((mode) => (
                    <button
                      key={mode}
                      onClick={() => handleChange('travelMode', mode)}
                      className={`flex flex-col items-center justify-center p-2 rounded-xl border transition-all ${
                        formData.travelMode === mode
                          ? 'bg-gray-900 border-gray-900 text-white'
                          : 'bg-white border-gray-200 text-gray-600 hover:border-gray-300'
                      }`}
                    >
                      {getModeIcon(mode)}
                      <span className="text-[10px] font-bold mt-1">{mode}</span>
                    </button>
                  ))}
                </div>

                {/* Route Preference (Car/Mixed) */}
                {(formData.travelMode === TravelMode.Car || formData.travelMode === TravelMode.Mixed) && (
                    <div className="mb-4 bg-gray-50 p-3 rounded-xl border border-gray-200">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2 block">Route Style</span>
                        <div className="flex gap-2">
                            {['fastest', 'scenic', 'avoidTolls'].map((pref) => (
                            <button
                                key={pref}
                                onClick={() => handleChange('routePreference', pref)}
                                className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all border ${
                                formData.routePreference === pref 
                                ? 'bg-white border-gray-300 text-gray-900 shadow-sm' 
                                : 'bg-transparent border-transparent text-gray-400 hover:text-gray-600'
                                }`}
                            >
                                {pref === 'avoidTolls' ? 'No Tolls' : pref === 'scenic' ? 'Scenic Route' : 'Fastest'}
                            </button>
                            ))}
                        </div>
                    </div>
                )}

                {/* Mixed Mode Multi-Leg Editor */}
                {formData.travelMode === TravelMode.Mixed && (
                  <div className="bg-gray-50 p-3 rounded-xl border border-gray-200 animate-in fade-in slide-in-from-top-1">
                      <div className="flex items-center gap-2 mb-3">
                        <Info className="w-3 h-3 text-gray-500" />
                        <span className="text-[10px] font-bold uppercase text-gray-500">Journey Legs</span>
                      </div>

                      <div className="space-y-2 mb-3">
                          {formData.mixedTravelLegs?.map((leg, i) => (
                              <div key={leg.id} className="bg-white border border-gray-200 rounded-lg p-2.5 shadow-sm group">
                                  <div className="flex items-center gap-2 mb-2">
                                      <span className="w-5 h-5 rounded bg-gray-100 flex items-center justify-center text-[10px] font-bold text-gray-500">{i + 1}</span>

                                      {/* Visual Icon for Leg */}
                                      <div className="text-gray-400">
                                         {getModeIcon(leg.mode)}
                                      </div>

                                      <select 
                                        value={leg.mode}
                                        onChange={(e) => updateLeg(leg.id, 'mode', e.target.value)}
                                        className="text-xs font-bold bg-gray-50 border border-gray-200 rounded px-1.5 py-1 focus:outline-none focus:border-blue-400"
                                      >
                                          <option value="Flight">Flight</option>
                                          <option value="Car">Car</option>
                                          <option value="Train">Train</option>
                                          <option value="Bus">Bus</option>
                                      </select>
                                      <div className="ml-auto">
                                          <button onClick={() => deleteLeg(leg.id)} className="text-gray-300 hover:text-red-500 transition-colors p-1">
                                              <X className="w-3.5 h-3.5" />
                                          </button>
                                      </div>
                                  </div>
                                  <div className="grid grid-cols-3 gap-2">
                                      <div className="col-span-2">
                                          <input 
                                            type="text" 
                                            placeholder="e.g. NYC to LON"
                                            value={leg.description}
                                            onChange={(e) => updateLeg(leg.id, 'description', e.target.value)}
                                            className="w-full text-xs border border-gray-200 rounded px-2 py-1.5 focus:outline-none focus:border-blue-400"
                                          />
                                      </div>
                                      <div>
                                          <input 
                                            type="text" 
                                            placeholder="Dur. (e.g. 7h)"
                                            value={leg.estimatedDuration}
                                            onChange={(e) => updateLeg(leg.id, 'estimatedDuration', e.target.value)}
                                            className="w-full text-xs border border-gray-200 rounded px-2 py-1.5 focus:outline-none focus:border-blue-400"
                                          />
                                      </div>
                                  </div>
                              </div>
                          ))}
                      </div>

                      <button 
                        onClick={addLeg}
                        className="w-full py-2 border border-dashed border-gray-300 rounded-lg text-xs font-bold text-gray-500 hover:bg-gray-100 hover:border-gray-400 transition-all flex items-center justify-center gap-1.5"
                      >
                          <Plus className="w-3.5 h-3.5" />
                          Add Travel Leg
                      </button>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div>
                      <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block flex items-center gap-1">
                        Max Drive Hours <Clock className="w-3 h-3" />
                      </span>
                      <div className="relative">
                          <select
                            value={formData.maxDriveHours}
                            onChange={(e) => handleChange('maxDriveHours', parseInt(e.target.value))}
                            className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2 px-3 text-sm font-bold text-gray-900 focus:outline-none focus:border-gray-400 appearance-none"
                          >
                            <option value={0}>Auto (Recommended)</option>
                            <option value={4}>4 Hours</option>
                            <option value={6}>6 Hours</option>
                            <option value={8}>8 Hours</option>
                            <option value={10}>10 Hours</option>
                            <option value={12}>12 Hours</option>
                          </select>
                          <ChevronDown className="w-4 h-4 text-gray-500 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
                      </div>
                  </div>
                   <div>
                      <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block">Target Stops</span>
                       <div className="relative">
                            <input
                            type="number"
                            min={1}
                            max={20}
                            value={formData.numberOfStops}
                            onChange={(e) => handleChange('numberOfStops', parseInt(e.target.value))}
                            className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2 px-3 text-sm font-bold text-gray-900 focus:outline-none focus:border-gray-400"
                            placeholder="Auto"
                          />
                       </div>
                  </div>
              </div>

           </div>
        </div>

      </div>

      <div className="p-4 lg:p-6 border-t border-gray-100 bg-white">
        <button
          onClick={() => onSubmit(formData, false)}
          disabled={isLoading}
          className={`w-full py-4 rounded-xl font-bold text-white text-lg shadow-[0_6px_20px_rgba(255,56,92,0.4)] transition-all transform hover:scale-[1.01] active:scale-[0.98] flex items-center justify-center gap-2 ${
            isLoading 
              ? 'bg-gray-300 cursor-not-allowed shadow-none' 
              : 'bg-gradient-to-r from-[#FF385C] to-[#BD1E59]'
          }`}
        >
          {isLoading ? (
             'Generating...' 
          ) : (
            <>
                <Search className="w-5 h-5" />
                Explore Plan
            </>
          )}
        </button>

        <button
          onClick={() => onSubmit(formData, true)}
          disabled={isLoading}
          className="w-full mt-3 py-3 rounded-xl font-bold text-gray-600 bg-transparent border border-gray-200 hover:bg-gray-50 transition-all text-sm"
        >
           Generate Alternative Route
        </button>
      </div>

      {/* --- Stop Editor Modal --- */}
      {isStopModalOpen && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-gray-900/40 backdrop-blur-[2px] p-4 animate-in fade-in duration-200">
           <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl p-6 animate-in zoom-in-95 duration-200 border border-gray-100">
              <div className="flex items-center justify-between mb-6">
                 <h3 className="text-lg font-black text-gray-800">
                   {editingIndex !== null ? 'Edit Stop' : 'Add Stop'}
                 </h3>
                 <button onClick={() => setIsStopModalOpen(false)} className="p-2 bg-gray-50 rounded-full hover:bg-gray-100 transition-colors">
                    <X className="w-5 h-5 text-gray-500" />
                 </button>
              </div>

              <div className="space-y-4">
                 <div>
                    <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">City Location</label>
                    <div className="relative">
                       <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                       <input 
                         type="text" 
                         value={tempStop.location}
                         onChange={handleCityInputChange}
                         onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                         className="w-full pl-9 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all placeholder-gray-400"
                         placeholder="e.g. Austin, TX"
                         autoFocus
                       />

                       {/* Autocomplete Dropdown */}
                       {showSuggestions && suggestions.length > 0 && (
                          <ul className="absolute z-50 w-full bg-white border border-gray-200 rounded-xl mt-1 shadow-xl max-h-48 overflow-y-auto animate-in fade-in zoom-in-95 duration-150">
                            {suggestions.map((city, idx) => (
                                <li 
                                    key={`${city}-${idx}`}
                                    onMouseDown={() => selectSuggestion(city)}
                                    className="px-4 py-3 hover:bg-gray-50 cursor-pointer text-sm font-bold text-gray-700 border-b border-gray-50 last:border-none flex items-center gap-2 group transition-colors"
                                >
                                    <div className="bg-gray-100 p-1 rounded-full group-hover:bg-[#FF385C] group-hover:text-white transition-colors">
                                       <MapPin className="w-3 h-3" />
                                    </div>
                                    {city}
                                </li>
                            ))}
                          </ul>
                       )}
                    </div>
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Arrival</label>
                      <div className="relative">
                         <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                         <input 
                           type="date" 
                           value={tempStop.arrivalDate || tempStop.date || ''}
                           onChange={(e) => handleTempStopChange('arrivalDate', e.target.value)}
                           className="w-full pl-9 pr-2 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 text-xs focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all appearance-none"
                         />
                      </div>
                    </div>
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Duration</label>
                      <div className="relative">
                         <Moon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                         <input 
                           type="number"
                           min={1}
                           max={14}
                           value={tempStop.nights}
                           onChange={(e) => handleTempStopChange('nights', parseInt(e.target.value) || 1)}
                           className="w-full pl-9 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all"
                         />
                         <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs font-bold text-gray-400 pointer-events-none">Nights</span>
                      </div>
                    </div>
                 </div>
              </div>

              <div className="flex items-center gap-3 mt-8">
                 {editingIndex !== null && (
                   <button 
                     onClick={deleteCurrentStop}
                     className="p-3.5 rounded-xl border border-red-100 text-red-500 hover:bg-red-50 hover:border-red-200 transition-colors"
                     title="Delete Stop"
                   >
                     <Trash2 className="w-5 h-5" />
                   </button>
                 )}
                 <button 
                   onClick={saveStop}
                   className="flex-1 py-3.5 bg-[#FF385C] text-white rounded-xl font-bold shadow-lg shadow-red-200 hover:bg-[#d9304e] transition-all flex items-center justify-center gap-2"
                 >
                   <Check className="w-5 h-5" />
                   {editingIndex !== null ? 'Save Changes' : 'Add Stop'}
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

{
  "name": "Road Trip Pro",
  "description": "Your AI-powered assistant for planning multi-city journeys, helping you discover opportunities.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React, { useState, useEffect, useCallback } from 'react';
import { Plus, X, MapPin, Calendar, Clock, Car, Bus, Plane, Shuffle, Search, Info, Edit2, Check, ChevronDown, AlertCircle, Sparkles, Trash2, Moon, Locate, LocateFixed, Train } from 'lucide-react';
import { TripFormData, TravelMode, MandatoryStop, ValidationErrors, MixedTravelLeg } from '../types';
import { DEFAULT_FORM_DATA } from '../constants';

interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
  validationErrors?: ValidationErrors;
}

const STORAGE_KEY = 'roadTripPro_formData';

const EMPTY_STOP: MandatoryStop = { location: '', date: '', arrivalDate: '', nights: 1 };

// Simulated Database for Autocomplete
const POPULAR_CITIES = [
  "New York, NY", "Los Angeles, CA", "Chicago, IL", "Houston, TX", "Phoenix, AZ",
  "Philadelphia, PA", "San Antonio, TX", "San Diego, CA", "Dallas, TX", "San Jose, CA",
  "Austin, TX", "Jacksonville, FL", "Fort Worth, TX", "Columbus, OH", "San Francisco, CA",
  "Charlotte, NC", "Indianapolis, IN", "Seattle, WA", "Denver, CO", "Washington, DC",
  "Boston, MA", "El Paso, TX", "Nashville, TN", "Detroit, MI", "Oklahoma City, OK",
  "Portland, OR", "Las Vegas, NV", "Memphis, TN", "Louisville, KY", "Baltimore, MD",
  "Milwaukee, WI", "Albuquerque, NM", "Tucson, AZ", "Fresno, CA", "Sacramento, CA",
  "Kansas City, MO", "Mesa, AZ", "Atlanta, GA", "Omaha, NE", "Colorado Springs, CO",
  "Raleigh, NC", "Miami, FL", "Long Beach, CA", "Virginia Beach, VA", "Oakland, CA",
  "Minneapolis, MN", "Tulsa, OK", "Tampa, FL", "Arlington, TX", "New Orleans, LA"
];

// Helper for robust ID generation across environments
const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    try {
      return crypto.randomUUID();
    } catch (e) {
      // Fallback if crypto exists but randomUUID fails (rare context issues)
    }
  }
  return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading, validationErrors }) => {
  // Initialize state from localStorage or fall back to initialData
  const [formData, setFormData] = useState<TripFormData>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      // Merge with default to ensure new fields like mixedTravelLegs exist
      return saved ? { ...DEFAULT_FORM_DATA, ...JSON.parse(saved) } : initialData;
    } catch (e) {
      console.warn('Failed to load form data from local storage', e);
      return initialData;
    }
  });

  // Modal State
  const [isStopModalOpen, setIsStopModalOpen] = useState(false);
  const [editingIndex, setEditingIndex] = useState<number | null>(null); // null means adding new
  const [tempStop, setTempStop] = useState<MandatoryStop>(EMPTY_STOP);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);

  // Autocomplete State for Stop Modal
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // Autocomplete State for Destination
  const [destSuggestions, setDestSuggestions] = useState<string[]>([]);
  const [showDestSuggestions, setShowDestSuggestions] = useState(false);

  // Persist to localStorage whenever formData changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
    } catch (e) {
      console.warn('Failed to save form data to local storage', e);
    }
  }, [formData]);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // --- Mixed Mode Legs Logic ---
  const addLeg = () => {
      const newLeg: MixedTravelLeg = {
          id: generateId(),
          mode: 'Flight',
          description: '',
          estimatedDuration: ''
      };
      handleChange('mixedTravelLegs', [...(formData.mixedTravelLegs || []), newLeg]);
  };

  const updateLeg = (id: string, field: keyof MixedTravelLeg, value: string) => {
      const updated = (formData.mixedTravelLegs || []).map(leg => 
          leg.id === id ? { ...leg, [field]: value } : leg
      );
      handleChange('mixedTravelLegs', updated);
  };

  const deleteLeg = (id: string) => {
      const updated = (formData.mixedTravelLegs || []).filter(leg => leg.id !== id);
      handleChange('mixedTravelLegs', updated);
  };

  // --- Geolocation Logic ---
  const performGeolocation = useCallback((isAuto: boolean) => {
    // Clear previous errors before starting
    setLocationError(null);

    if (!navigator.geolocation) {
      if (!isAuto) setLocationError("Geolocation is not supported by your browser");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;

        try {
            // Using BigDataCloud API for reliable city/state names (Free, robust for client-side)
            const response = await fetch(
                `https://api.bigdatacloud.net/data/reverse-geocode-client?latitude=${latitude}&longitude=${longitude}&localityLanguage=en`
            );

            if (!response.ok) throw new Error('Geocoding failed');

            const data = await response.json();

            // Extract meaningful names with fallbacks
            const city = data.city || data.locality || '';
            const state = data.principalSubdivisionCode || data.principalSubdivision || '';
            const country = data.countryCode || '';

            let locString = '';

            if (city) {
                locString = city;
                if (state) locString += `, ${state}`;
                else if (country) locString += `, ${country}`;
            } else if (state) {
                 // Fallback: State, Country if city is undefined (rural areas)
                 locString = `${state}, ${country}`;
            }

            if (!locString.trim()) {
                 locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;
            }

            setFormData(prev => ({ ...prev, origin: locString }));
        } catch (error) {
            console.warn("Reverse geocoding failed", error);
            const locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;
            setFormData(prev => ({ ...prev, origin: locString }));
        } finally {
            setIsLocating(false);
        }
      },
      (error) => {
        console.error("Geolocation error:", error);
        if (!isAuto) {
            let msg = "Unable to retrieve location";
            if (error.code === 1) msg = "Location permission denied";
            else if (error.code === 2) msg = "Position unavailable";
            else if (error.code === 3) msg = "Request timed out";
            setLocationError(msg);
        }
        setIsLocating(false);
      }
    );
  }, []);

  useEffect(() => {
    if (!formData.origin) {
        performGeolocation(true);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleGeolocationClick = () => {
    performGeolocation(false);
  };

  // --- Modal Logic ---

  const openAddStopModal = () => {
    setTempStop({ ...EMPTY_STOP });
    setSuggestions([]);
    setShowSuggestions(false);
    setEditingIndex(null);
    setIsStopModalOpen(true);
  };

  const openEditStopModal = (index: number) => {
    setTempStop({ ...formData.mandatoryStops[index] });
    setSuggestions([]);
    setShowSuggestions(false);
    setEditingIndex(index);
    setIsStopModalOpen(true);
  };

  const handleTempStopChange = (field: keyof MandatoryStop, value: string | number) => {
    setTempStop(prev => ({ ...prev, [field]: value }));
  };

  // Stop Autocomplete Logic
  const handleCityInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    handleTempStopChange('location', value);

    if (value.length > 1) {
      const filtered = POPULAR_CITIES.filter(city => 
        city.toLowerCase().includes(value.toLowerCase())
      ).slice(0, 5); // Limit to 5 suggestions
      setSuggestions(filtered);
      setShowSuggestions(true);
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
    }
  };

  const selectSuggestion = (city: string) => {
    handleTempStopChange('location', city);
    setShowSuggestions(false);
  };

  // Destination Autocomplete Logic
  const handleDestinationChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    handleChange('destination', value);

    if (value.length > 1) {
      const filtered = POPULAR_CITIES.filter(city => 
        city.toLowerCase().includes(value.toLowerCase())
      ).slice(0, 5); 
      setDestSuggestions(filtered);
      setShowDestSuggestions(true);
    } else {
      setDestSuggestions([]);
      setShowDestSuggestions(false);
    }
  };

  const selectDestSuggestion = (city: string) => {
    handleChange('destination', city);
    setShowDestSuggestions(false);
  };

  const saveStop = () => {
    const newStops = [...formData.mandatoryStops];
    if (editingIndex !== null) {
      newStops[editingIndex] = tempStop;
    } else {
      newStops.push(tempStop);
    }
    handleChange('mandatoryStops', newStops);
    setIsStopModalOpen(false);
  };

  const removeStop = (index: number) => {
    const newStops = formData.mandatoryStops.filter((_, i) => i !== index);
    handleChange('mandatoryStops', newStops);
  };

