                 >
                   <Check className="w-5 h-5" />
                   {editingIndex !== null ? 'Save Changes' : 'Add Stop'}
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export enum TravelMode {
  Car = 'Car',
  Bus = 'Bus',
  Plane = 'Plane',
  Mixed = 'Mixed'
}

export type RoutePreference = 'fastest' | 'scenic' | 'avoidTolls';

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface Stop {
  city: string;
  day: number;
  activity: string;
  profitabilityJustification: string;
  demandScore: number; // 0-100
  trendVelocity: string;
  clusterInfo?: {
    anchorCity: string;
    clusterVolume: string;
  };
  travelToNext: string;
  travelTimeFromPrev?: string;
  transportMode?: string;
  trafficCondition?: string;
  nightsToStay: number;
  targetArrivalDate?: string;
  coordinates?: {
    lat: number;
    lng: number;
  };
  stopSources?: GroundingSource[]; // Sources specific to this city/stop
}

export interface Itinerary {
  origin?: string;
  destination?: string;
  routeName: string;
  totalDistance: string;
  totalDuration: string;
  stops: Stop[];
