                 </div>

                 <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Arrival</label>
                      <div className="relative">
                         <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                         <input 
                           type="date" 
                           value={tempStop.arrivalDate || tempStop.date || ''}
                           onChange={(e) => handleTempStopChange('arrivalDate', e.target.value)}
                           className="w-full pl-9 pr-2 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 text-xs focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all appearance-none"
                         />
                      </div>
                    </div>
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Duration</label>
                      <div className="relative">
                         <Moon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                         <input 
                           type="number"
                           min={1}
                           max={14}
                           value={tempStop.nights}
                           onChange={(e) => handleTempStopChange('nights', parseInt(e.target.value) || 1)}
                           className="w-full pl-9 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all"
                         />
                         <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs font-bold text-gray-400 pointer-events-none">Nights</span>
                      </div>
                    </div>
                 </div>
              </div>

              <div className="flex items-center gap-3 mt-8">
                 {editingIndex !== null && (
                   <button 
                     onClick={deleteCurrentStop}
                     className="p-3.5 rounded-xl border border-red-100 text-red-500 hover:bg-red-50 hover:border-red-200 transition-colors"
                     title="Delete Stop"
                   >
                     <Trash2 className="w-5 h-5" />
                   </button>
                 )}
                 <button 
                   onClick={saveStop}
                   className="flex-1 py-3.5 bg-[#FF385C] text-white rounded-xl font-bold shadow-lg shadow-red-200 hover:bg-[#d9304e] transition-all flex items-center justify-center gap-2"
                 >
                   <Check className="w-5 h-5" />
                   {editingIndex !== null ? 'Save Changes' : 'Add Stop'}
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export enum TravelMode {
  Car = 'Car',
  Bus = 'Bus',
  Plane = 'Plane',
  Mixed = 'Mixed'
}

export type RoutePreference = 'fastest' | 'scenic' | 'avoidTolls';

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface Stop {
  city: string;
  day: number;
  activity: string;
  profitabilityJustification: string;
  demandScore: number; // 0-100
  trendVelocity: string;
  clusterInfo?: {
    anchorCity: string;
    clusterVolume: string;
  };
  travelToNext: string;
  travelTimeFromPrev?: string;
  transportMode?: string;
  trafficCondition?: string;
  nightsToStay: number;
  targetArrivalDate?: string;
  coordinates?: {
    lat: number;
    lng: number;
  };
  stopSources?: GroundingSource[]; // Sources specific to this city/stop
}

export interface Itinerary {
  origin?: string;
  destination?: string;
  routeName: string;
  totalDistance: string;
  totalDuration: string;
  stops: Stop[];
  summary: string;
  startDate?: string;
  travelMode?: TravelMode;
  sources?: GroundingSource[];
}

export interface MandatoryStop {
  location: string;
  date: string;
  arrivalDate?: string;
  nights: number;
}

export interface MixedTravelLeg {
  id: string;
  mode: string; // e.g., 'Flight', 'Car', 'Train'
  description: string; // e.g., 'JFK to LHR'
  estimatedDuration: string; // e.g., '7h'
}

export interface TripFormData {
  origin: string;
  destination: string;
  destinationDate: string;
  startDate: string;
  endDate: string;
  mandatoryStops: MandatoryStop[];
  numberOfStops: number;
  maxDriveHours: number;
  travelMode: TravelMode;
  travelModeDetail?: string;
  mixedTravelLegs: MixedTravelLeg[];
  routePreference: RoutePreference;
}

export interface MarketInsight {
  trendingKeywords: {
    keyword: string;
    volume: number;
    growth: string;
  }[];
  topClusters: {
    city: string;
    score: number;
    tags: string[];
  }[];
  seasonalAdvice: string;
  lastUpdated: string;
}

export interface AppSettings {
  defaultTravelMode: TravelMode;
  units: 'imperial' | 'metric';
  currency: string;
}

export interface SavedTrip {
  id: string;
  name: string;
  createdDate: string;
  formData: TripFormData;
  itinerary: Itinerary;
}

export type ValidationErrors = Record<string, { message: string; suggestion: string }>;

import React, { useState, useEffect, useCallback } from 'react';
import { Plus, X, MapPin, Calendar, Clock, Car, Bus, Plane, Shuffle, Search, Info, Edit2, Check, ChevronDown, AlertCircle, Sparkles, Trash2, Moon, Locate, LocateFixed, Train } from 'lucide-react';
import { TripFormData, TravelMode, MandatoryStop, ValidationErrors, MixedTravelLeg } from '../types';
import { DEFAULT_FORM_DATA } from '../constants';

interface InputFormProps {
  initialData: TripFormData;
  importedData?: TripFormData | null;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
  validationErrors?: ValidationErrors;
}

const STORAGE_KEY = 'roadTripPro_formData';

const EMPTY_STOP: MandatoryStop = { location: '', date: '', arrivalDate: '', nights: 1 };

// Simulated Database for Autocomplete
const POPULAR_CITIES = [
  "New York, NY", "Los Angeles, CA", "Chicago, IL", "Houston, TX", "Phoenix, AZ",
  "Philadelphia, PA", "San Antonio, TX", "San Diego, CA", "Dallas, TX", "San Jose, CA",
  "Austin, TX", "Jacksonville, FL", "Fort Worth, TX", "Columbus, OH", "San Francisco, CA",
  "Charlotte, NC", "Indianapolis, IN", "Seattle, WA", "Denver, CO", "Washington, DC",
  "Boston, MA", "El Paso, TX", "Nashville, TN", "Detroit, MI", "Oklahoma City, OK",
  "Portland, OR", "Las Vegas, NV", "Memphis, TN", "Louisville, KY", "Baltimore, MD",
  "Milwaukee, WI", "Albuquerque, NM", "Tucson, AZ", "Fresno, CA", "Sacramento, CA",
  "Kansas City, MO", "Mesa, AZ", "Atlanta, GA", "Omaha, NE", "Colorado Springs, CO",
  "Raleigh, NC", "Miami, FL", "Long Beach, CA", "Virginia Beach, VA", "Oakland, CA",
  "Minneapolis, MN", "Tulsa, OK", "Tampa, FL", "Arlington, TX", "New Orleans, LA"
];

// Helper for robust ID generation across environments
const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    try {
      return crypto.randomUUID();
    } catch (e) {
      // Fallback if crypto exists but randomUUID fails (rare context issues)
    }
  }
  return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

export const InputForm: React.FC<InputFormProps> = ({ initialData, importedData, onSubmit, isLoading, validationErrors }) => {
  // Initialize state from localStorage or fall back to initialData
  const [formData, setFormData] = useState<TripFormData>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      // Merge with default to ensure new fields like mixedTravelLegs exist
      return saved ? { ...DEFAULT_FORM_DATA, ...JSON.parse(saved) } : initialData;
    } catch (e) {
      console.warn('Failed to load form data from local storage', e);
      return initialData;
    }
  });

  // Effect to load imported data (from Saved Trips)
  useEffect(() => {
    if (importedData) {
        setFormData(importedData);
    }
  }, [importedData]);

  // Modal State
  const [isStopModalOpen, setIsStopModalOpen] = useState(false);
  const [editingIndex, setEditingIndex] = useState<number | null>(null); // null means adding new
  const [tempStop, setTempStop] = useState<MandatoryStop>(EMPTY_STOP);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);

  // Autocomplete State for Stop Modal
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // Autocomplete State for Origin
  const [originSuggestions, setOriginSuggestions] = useState<string[]>([]);
  const [showOriginSuggestions, setShowOriginSuggestions] = useState(false);

  // Autocomplete State for Destination
  const [destSuggestions, setDestSuggestions] = useState<string[]>([]);
  const [showDestSuggestions, setShowDestSuggestions] = useState(false);

  // Persist to localStorage whenever formData changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
    } catch (e) {
      console.warn('Failed to save form data to local storage', e);
    }
  }, [formData]);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // --- Mixed Mode Legs Logic ---
  const addLeg = () => {
      const newLeg: MixedTravelLeg = {
          id: generateId(),
          mode: 'Flight',
          description: '',
          estimatedDuration: ''
      };
      handleChange('mixedTravelLegs', [...(formData.mixedTravelLegs || []), newLeg]);
  };

  const updateLeg = (id: string, field: keyof MixedTravelLeg, value: string) => {
      const updated = (formData.mixedTravelLegs || []).map(leg => 
          leg.id === id ? { ...leg, [field]: value } : leg
      );
      handleChange('mixedTravelLegs', updated);
  };

  const deleteLeg = (id: string) => {
      const updated = (formData.mixedTravelLegs || []).filter(leg => leg.id !== id);
      handleChange('mixedTravelLegs', updated);
  };

  // --- Geolocation Logic ---
  const performGeolocation = useCallback((isAuto: boolean) => {
    // Clear previous errors before starting
    setLocationError(null);

    if (!navigator.geolocation) {
      if (!isAuto) setLocationError("Geolocation is not supported by your browser");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;

        try {
            // Using BigDataCloud API for reliable city/state names (Free, robust for client-side)
            const response = await fetch(
                `https://api.bigdatacloud.net/data/reverse-geocode-client?latitude=${latitude}&longitude=${longitude}&localityLanguage=en`
            );

            if (!response.ok) throw new Error('Geocoding failed');

            const data = await response.json();

            // Extract meaningful names with fallbacks
            const city = data.city || data.locality || '';
            const state = data.principalSubdivisionCode || data.principalSubdivision || '';
            const country = data.countryCode || '';

            let locString = '';

            if (city) {
                locString = city;
                if (state) locString += `, ${state}`;
                else if (country) locString += `, ${country}`;
            } else if (state) {
                 // Fallback: State, Country if city is undefined (rural areas)
                 locString = `${state}, ${country}`;
            }

            if (!locString.trim()) {
                 locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;
            }

            setFormData(prev => ({ ...prev, origin: locString }));
        } catch (error) {
            console.warn("Reverse geocoding failed", error);
            const locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;
            setFormData(prev => ({ ...prev, origin: locString }));
        } finally {
            setIsLocating(false);
        }
      },
      (error) => {
        console.error("Geolocation error:", error);
        if (!isAuto) {
            let msg = "Unable to retrieve location.";
            if (error.code === 1) {
                // PERMISSION_DENIED
                msg = "Location access denied. Please enable location permissions in your browser settings (click the lock icon in the address bar) and try again.";
            } else if (error.code === 2) {
