import { MarketInsights } from './components/MarketInsights';
import { ErrorBanner } from './components/ErrorBanner';
import { SettingsModal } from './components/SettingsModal';
import { ProfileView } from './components/ProfileView';
import { useItinerary } from './hooks/useItinerary';
import { useMarketInsights } from './hooks/useMarketInsights';
import { DEFAULT_FORM_DATA, DEFAULT_SETTINGS } from './constants';
import { AppSettings, SavedTrip, Itinerary, TripFormData } from './types';
import { MapPin, TrendingUp, Compass, Settings, User } from 'lucide-react';

type ViewMode = 'planner' | 'insights' | 'profile';

const SETTINGS_STORAGE_KEY = 'roadTripPro_settings';
const TRIPS_STORAGE_KEY = 'roadTripPro_savedTrips';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewMode>('planner');
  const [showResultsMobile, setShowResultsMobile] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // App Settings State
  const [appSettings, setAppSettings] = useState<AppSettings>(() => {
    try {
        const saved = localStorage.getItem(SETTINGS_STORAGE_KEY);
        return saved ? JSON.parse(saved) : DEFAULT_SETTINGS;
    } catch {
        return DEFAULT_SETTINGS;
    }
  });

  // Saved Trips State
  const [savedTrips, setSavedTrips] = useState<SavedTrip[]>(() => {
    try {
      const saved = localStorage.getItem(TRIPS_STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch {
      return [];
    }
  });

  // State to pass data to InputForm when loading a trip
  const [importedFormData, setImportedFormData] = useState<TripFormData | null>(null);

  useEffect(() => {
    localStorage.setItem(TRIPS_STORAGE_KEY, JSON.stringify(savedTrips));
  }, [savedTrips]);

  const handleSaveSettings = (newSettings: AppSettings) => {
      setAppSettings(newSettings);
      localStorage.setItem(SETTINGS_STORAGE_KEY, JSON.stringify(newSettings));
  };

  // Use Custom Hooks
  const { 
    itinerary, 
    isLoading, 
    error, 
    validationErrors, 
    lastData, 
    handleGenerate, 
    setError,
    setItinerary // We need to expose this to set itinerary from saved trip
  } = useItinerary();

  const { insights, isInsightsLoading, fetchInsights } = useMarketInsights();

  const onFormSubmit = async (data: any, isAlt: boolean) => {
    const success = await handleGenerate(data, isAlt);
    if (success && window.innerWidth < 1024) {
      setShowResultsMobile(true);
    }
  };

  const switchView = (view: ViewMode) => {
    setCurrentView(view);
    // Lazy load insights when switching to tab if not already loaded
    if (view === 'insights' && !insights && !isInsightsLoading) {
        fetchInsights();
    }
  };

  // Trip Management Handlers
  const handleSaveTrip = (itineraryToSave: Itinerary) => {
     if (!lastData) return;

     const newTrip: SavedTrip = {
       id: Date.now().toString(),
       name: itineraryToSave.routeName || `Trip to ${lastData.destination}`,
       createdDate: new Date().toISOString(),
       formData: lastData,
       itinerary: itineraryToSave
     };

     setSavedTrips(prev => [newTrip, ...prev]);
  };

  const handleDeleteTrip = (id: string) => {
    setSavedTrips(prev => prev.filter(t => t.id !== id));
  };

  const handleLoadTrip = (trip: SavedTrip) => {
    setImportedFormData(trip.formData);
    // Directly set the itinerary in the hook to show results immediately
    // Note: You need to modify useItinerary to return setItinerary or expose a way to set it
    // For now, assuming useItinerary returns setItinerary (added in comment above)
    // If not, we might need to re-trigger generation or just rely on form data load

    // We will update useItinerary hook to allow external setItinerary call 
    // OR we force a regeneration. But forcing regeneration costs API tokens.
    // Ideally we just display the saved result.
    // Check useItinerary hook update below.
    if ((setItinerary as any)) {
      (setItinerary as any)(trip.itinerary);
    }

    setCurrentView('planner');
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-[#222222] font-sans">
      {/* Header Section */}
      <header className="flex-none bg-white border-b border-gray-200 z-50 sticky top-0 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 text-[#FF385C] cursor-pointer" onClick={() => switchView('planner')}>
            <MapPin className="w-8 h-8 fill-current" />
            <h1 className="text-2xl font-bold tracking-tight text-[#FF385C] hidden sm:block">
              RoadTripPro
            </h1>
          </div>

          <nav className="flex items-center gap-6">
            <NavButton 
              active={currentView === 'planner'} 
              onClick={() => switchView('planner')} 
              icon={<Compass className="w-4 h-4" />}
              label="Road Trip" 
            />
            <NavButton 
              active={currentView === 'insights'} 
              onClick={() => switchView('insights')} 
              icon={<TrendingUp className="w-4 h-4" />}
              label="Market Insights" 
            />
          </nav>

          <div className="flex items-center gap-3">
             <button 
                onClick={() => setIsSettingsOpen(true)}
                className="w-10 h-10 rounded-full bg-white border border-gray-200 flex items-center justify-center text-gray-500 hover:text-gray-800 hover:shadow-md transition-all"
                title="Settings"
             >
                <Settings className="w-5 h-5" />
             </button>
             <div 
                onClick={() => switchView('profile')}
                className={`w-10 h-10 rounded-full border flex items-center justify-center cursor-pointer transition-all ${currentView === 'profile' ? 'bg-gray-800 text-white border-gray-800' : 'bg-gray-100 border-gray-200 text-gray-500 hover:shadow-md'}`}
             >
                <span className="text-xs font-bold">JD</span>
             </div>
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        <div className="max-w-7xl mx-auto h-full p-0 lg:p-6">

          {currentView === 'planner' ? (
             <div className="flex flex-col lg:flex-row gap-8 h-full">
                {/* Form Column */}
                <div className={`w-full lg:w-[400px] flex-none h-full bg-white lg:rounded-2xl lg:shadow-xl lg:border lg:border-gray-100 overflow-hidden flex flex-col z-20 transition-transform duration-300 ${showResultsMobile ? '-translate-x-full absolute' : 'translate-x-0 relative'} lg:translate-x-0 lg:relative`}>
                    <InputForm 
                      initialData={DEFAULT_FORM_DATA} 
                      importedData={importedFormData}
                      onSubmit={onFormSubmit}
                      isLoading={isLoading}
                      validationErrors={validationErrors}
                    />
                    {error && (
                        <ErrorBanner message={error} onClose={() => setError(null)} />
                    )}
                </div>

                {/* Display Column */}
                <div className={`flex-1 h-full overflow-hidden bg-white lg:bg-transparent rounded-none lg:rounded-2xl relative transition-transform duration-300 ${showResultsMobile ? 'translate-x-0 absolute inset-0 z-30' : 'translate-x-full absolute'} lg:translate-x-0 lg:relative lg:inset-auto lg:z-0`}>
                    {showResultsMobile && (
                        <div className="lg:hidden absolute top-4 left-4 z-50">
                            <button 
                            onClick={() => setShowResultsMobile(false)}
                            className="bg-white p-2 rounded-full shadow-lg border border-gray-100 text-gray-700 font-bold text-sm px-4 flex items-center gap-2"
                            >
                            <span>←</span> Edit Plan
