        message.includes('429') || 
        message.includes('quota') || 
        message.includes('resource_exhausted') || 
        message.includes('overloaded')
    );
};

// Exponential Backoff Retry Helper
const withRetry = async <T>(
    operation: () => Promise<T>,
    maxRetries: number = 3,
    baseDelay: number = 1000,
    shouldRetry: (error: any) => boolean = () => true
): Promise<T> => {
    let lastError: any;

    for (let attempt = 0; attempt < maxRetries; attempt++) {
        try {
            return await operation();
        } catch (error: any) {
            lastError = error;

            // Check if we should retry this specific error
            if (!shouldRetry(error)) {
                throw error;
            }

            // If it's the last attempt, don't wait, just throw
            if (attempt === maxRetries - 1) {
                throw error;
            }

            // Exponential backoff with jitter
            const delay = baseDelay * Math.pow(2, attempt) + (Math.random() * 200);
            console.warn(`[Gemini Service] Attempt ${attempt + 1} failed. Retrying in ${Math.round(delay)}ms...`, error.message);
            await new Promise(resolve => setTimeout(resolve, delay));
        }
    }
    throw lastError;
};

// Retry predicate for the Pro model (Primary)
// We want to retry transient network/server errors, but fail fast on Quota (429) so we can fallback to Flash.
const shouldRetryPro = (error: any) => {
    const code = error.status || error.code;
    const msg = (error.message || '').toLowerCase();

    // 5xx are server errors, usually transient
    if (code >= 500 && code < 600) return true;

    // Network errors
    if (msg.includes('network') || msg.includes('fetch') || msg.includes('failed to fetch')) return true;

    // 429 (Quota) - Return FALSE to trigger immediate fallback
    if (code === 429 || msg.includes('quota') || msg.includes('resource_exhausted')) return false;

    return false;
};

// Retry predicate for the Flash model (Fallback)
// We retry everything reasonable here, including 429, because we have nowhere else to go.
const shouldRetryFlash = (error: any) => {
    const code = error.status || error.code;
    const msg = (error.message || '').toLowerCase();

    if (code === 429 || msg.includes('quota') || msg.includes('resource_exhausted')) return true;
    if (code >= 500 && code < 600) return true;
    if (msg.includes('network') || msg.includes('fetch') || msg.includes('failed to fetch')) return true;

    return false;
};

