        return {
            ...stop,
            stopSources: stopSources.length > 0 ? Array.from(new Map(stopSources.map(s => [s.uri, s])).values()) : undefined
        };
    });

    result.startDate = data.startDate;
    result.origin = data.origin || result.stops[0]?.city || "Unknown Start";
    result.destination = data.destination || result.stops[result.stops.length - 1]?.city || "Unknown End";

    result.stops.sort((a, b) => a.day - b.day);

    return result;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error(error.message || "Route calculation failed. Check your API key and network.");
  }
};

export const generateMarketInsights = async (): Promise<MarketInsight> => {
    const ai = getClient();
    const today = new Date().toISOString().split('T')[0];
    const prompt = `
      DATE: ${today}. 
      TASK: Generate a Market Intelligence Report for the US 'Male Massage & Wellness' sector.
      KEYWORDS: gay massage, sensual massage, male massage therapist, gay spa massage.

      LIMITS:
      - Limit to top 10 Trending Keywords.
      - Limit to top 5 City Clusters.
      - Ensure purely valid JSON output.
    `;

    const insightSchema = {
      type: Type.OBJECT,
      properties: {
        trendingKeywords: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              keyword: { type: Type.STRING },
              volume: { type: Type.NUMBER },
              growth: { type: Type.STRING },
            }
          }
        },
        topClusters: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              city: { type: Type.STRING },
              score: { type: Type.NUMBER },
              tags: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          }
        },
        seasonalAdvice: { type: Type.STRING },
        lastUpdated: { type: Type.STRING },
      },
      required: ["trendingKeywords", "topClusters", "seasonalAdvice"],
    };

    const modelConfig = {
        maxOutputTokens: 8192,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: insightSchema,
    };

    try {
      let response;
      try {
          // Attempt 1: Pro Model
          response = await withRetry(
            () => ai.models.generateContent({
                model: GEMINI_MODEL,
                contents: prompt,
                config: modelConfig,
            }),
            3,
            1000,
            shouldRetryPro
          );
      } catch (error: any) {
        if (isQuotaError(error) || error.status >= 500 || error.message?.includes('fetch')) {
            console.warn("Pro model failed for Insights, fallback to Flash.", error);
            // Fallback: Flash Model
            response = await withRetry(
                () => ai.models.generateContent({
                    model: GEMINI_FLASH_MODEL,
                    contents: prompt,
                    config: modelConfig,
                }),
                3,
                1000,
                shouldRetryFlash
            );
        } else {
            throw error;
        }
      }

      const text = response.text;
      if (!text) {
          throw new Error("No insights generated");
      }

      const cleanText = cleanJsonString(text);
      let result: MarketInsight;

      try {
        result = JSON.parse(cleanText) as MarketInsight;
      } catch (e) {
        console.error("JSON Parse Error. Raw Text:", text);
        console.error("Cleaned Text:", cleanText);
        throw e;
      }

      return { ...result, lastUpdated: today };
    } catch (error) {
      console.error("Insights Error:", error);
      throw error;
    }
};
